  ('judicial-57f41407-moex-00277', 'judicial-57f41407', 'judicial-57f41407-moex-113-1611a566', 'sub-judicial-57f41407-03', NULL, 'single_choice', '關於刑事訴訟法第131條緊急搜索之敘述，下列何者錯誤？', '["搜索，由檢察官為之者，應於實施後3日內陳報該管法院", "由司法警察官為之者，應於執行後3日內報告該管檢察署檢察官及法院", "法院認為不應准許者，應於7日內撤銷之", "搜索執行後未陳報該管法院或經法院撤銷者，審判時法院得宣告所扣得之物，不得作為證據"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:38+00:00", "source_pdf_sha1": "5eb59e12bd0e", "answer_pdf_sha1": "fb67b130acc0", "source_family": "moex-gov-tw", "moex": {"exam_code": "113120", "c": "301", "s": "0409", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "113", "exam_name": "113年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
